INSERT INTO patient_profiles (profile_id, user_id, age, gender, height_cm, base_weight_kg, base_waist_cm, family_history, chronic_history, allergy_history, create_time, update_time) VALUES
(1, 2, 46, 'male', 172.0, 82.5, 96.0, '父亲有2型糖尿病史，母亲有高血压史。', '近两年体重上升，血压偶有偏高，暂无明确糖尿病诊断。', '无明确药物或食物过敏史。', '2026-06-01 08:15:00', '2026-06-26 20:10:00'),
(2, 3, 38, 'female', 164.0, 66.0, 82.0, '外婆曾患2型糖尿病。', '妊娠期曾出现血糖偏高，产后复查基本正常。', '青霉素过敏。', '2026-06-03 09:20:00', '2026-06-26 18:40:00'),
(3, 4, 59, 'female', 158.0, 70.5, 91.0, '哥哥有糖尿病史。', '高血压病史6年，规律服药，近期关注体重和餐后血糖。', '无。', '2026-06-05 10:30:00', '2026-06-27 07:50:00'),
(4, 5, 52, 'male', 176.0, 88.0, 101.0, '父母均有代谢类慢病史。', '血脂偏高，工作应酬较多，近期打卡中断。', '海鲜轻度过敏。', '2026-06-08 11:20:00', '2026-06-18 19:30:00');
INSERT INTO health_metrics (metric_id, user_id, weight_kg, waist_cm, systolic_bp, diastolic_bp, fasting_glucose, postprandial_glucose, hba1c, diet_status, exercise_status, recorded_at, create_time) VALUES
(1, 2, 82.5, 96.0, 136, 86, 6.8, 9.9, 6.2, '早餐白粥和包子较多，午餐外卖偏油，晚餐有时较晚。', '每周散步2次，每次约20分钟。', '2026-06-12 07:30:00', '2026-06-12 07:35:00'),
(2, 2, 82.1, 95.5, 132, 84, 6.5, 9.2, 6.1, '开始减少含糖饮料，晚餐主食减半。', '饭后散步增加到每周4次。', '2026-06-18 07:40:00', '2026-06-18 07:45:00'),
(3, 2, 81.6, 95.0, 130, 82, 6.2, 8.6, 6.0, '早餐加入鸡蛋和蔬菜，午餐注意少油。', '近7天完成5次饭后步行。', '2026-06-26 07:25:00', '2026-06-26 07:30:00'),
(4, 3, 66.0, 82.0, 118, 76, 5.7, 7.6, 5.8, '三餐较规律，水果集中在两餐之间。', '瑜伽2次，通勤步行较多。', '2026-06-11 08:10:00', '2026-06-11 08:15:00'),
(5, 3, 65.6, 81.5, 116, 74, 5.5, 7.2, 5.7, '主食粗细搭配，晚间零食减少。', '每周3次轻中强度运动。', '2026-06-19 08:00:00', '2026-06-19 08:04:00'),
(6, 3, 65.2, 81.0, 115, 73, 5.4, 6.9, 5.6, '饮食稳定，偶尔外食也能控制饮料和主食量。', '运动规律，睡眠改善。', '2026-06-26 08:05:00', '2026-06-26 08:08:00'),
(7, 4, 70.5, 91.0, 146, 90, 7.1, 10.4, 6.6, '午餐主食偏多，晚餐偏咸，蔬菜不足。', '运动较少，主要是家务活动。', '2026-06-10 07:20:00', '2026-06-10 07:25:00'),
(8, 4, 70.0, 90.5, 142, 88, 6.8, 9.8, 6.4, '减少腌制食物，尝试餐盘法。', '饭后慢走3次，每次15分钟。', '2026-06-18 07:10:00', '2026-06-18 07:15:00'),
(9, 4, 69.6, 89.8, 138, 84, 6.5, 9.0, 6.2, '晚餐提前，蔬菜量增加。', '近一周慢走5次，强度温和。', '2026-06-27 07:05:00', '2026-06-27 07:10:00'),
(10, 5, 88.0, 101.0, 150, 94, 7.4, 11.2, 6.9, '应酬较多，饮酒和夜宵频率偏高。', '近两周运动明显减少。', '2026-06-16 08:30:00', '2026-06-16 08:35:00'),
(11, 5, 88.6, 102.0, 152, 96, 7.6, 11.8, 7.0, '连续外食，主食和油盐控制不足。', '打卡中断，暂无固定运动。', '2026-06-18 08:20:00', '2026-06-18 08:25:00');
INSERT INTO risk_assessments (assessment_id, user_id, metric_id, request_summary, response_result, risk_level, risk_score, diabetes_type_tendency, main_risk_factors, indicator_analysis, health_advice, medical_warning, summary, call_status, error_message, create_time) VALUES
(1, 2, 3, '46岁男性，有家族史，BMI偏高，近期空腹血糖6.2mmol/L，餐后血糖8.6mmol/L。', '{"risk_level":"medium","risk_score":64}', 'medium', 64, '2型糖尿病风险倾向', '["家族史", "腰围偏高", "餐后血糖偏高"]', '空腹和餐后血糖均较前期下降，但仍需持续观察；血压处于临界偏高区间。', '继续保持餐盘法和饭后步行，建议每周至少150分钟中等强度活动，并记录餐后血糖趋势。', '若空腹血糖连续升高或出现多饮、多尿、明显乏力，应及时线下复查。', '整体风险中等，近期改善明显，重点是保持体重和餐后血糖下降趋势。', 'success', NULL, '2026-06-26 09:00:00'),
(2, 3, 6, '38岁女性，有妊娠期血糖偏高史，当前体重和血糖趋势稳定。', '{"risk_level":"low","risk_score":34}', 'low', 34, '糖尿病前期需随访', '["妊娠期血糖异常史", "家族史"]', '当前空腹和餐后血糖处于较稳定状态，血压正常，体重轻度下降。', '维持规律运动和粗细搭配饮食，继续关注睡眠和压力。', '年度体检中保留糖化血红蛋白复查，妊娠或体重变化时需更密切随访。', '当前风险较低，但因既往史仍需保持长期随访。', 'success', NULL, '2026-06-26 09:20:00'),
(3, 4, 9, '59岁女性，高血压病史，空腹血糖6.5mmol/L，餐后9.0mmol/L，近期体重略降。', '{"risk_level":"high","risk_score":78}', 'high', 78, '2型糖尿病高风险', '["年龄", "高血压", "腰围偏高", "血糖偏高", "家族史"]', '血糖较前下降但仍偏高，血压控制较前改善，腰围仍需重点管理。', '在医生建议下复查空腹血糖、餐后血糖和糖化血红蛋白；饮食上减少精白主食和高盐食物，运动以温和步行为主。', '如血糖继续偏高或血压波动，应尽快线下就诊评估，不建议自行调整降压药。', '风险偏高但已有改善迹象，应把复查和持续生活方式干预作为下一阶段重点。', 'success', NULL, '2026-06-27 09:00:00'),
(4, 5, 11, '52岁男性，腰围和血压偏高，近期外食饮酒较多，打卡中断。', '{"risk_level":"high","risk_score":86}', 'high', 86, '2型糖尿病高风险', '["血糖偏高", "血压偏高", "腰围偏高", "运动不足", "饮酒和夜宵"]', '空腹和餐后血糖均处于明显偏高状态，糖化血红蛋白提示近阶段整体控制不理想。', '先恢复每日记录，减少酒精和夜宵，优先安排线下复查并获得医生评估。', '该用户已停用账号用于管理端异常/停用展示；如恢复使用，应先完成线下复查。', '高风险且依从性下降，需要管理端重点随访。', 'success', NULL, '2026-06-18 09:00:00');
INSERT INTO life_plans (plan_id, user_id, profile_id, metric_id, assessment_id, plan_title, plan_goal, input_summary, plan_json, checkin_tasks_json, summary, status, call_status, error_message, create_time, update_time) VALUES
(1, 2, 1, 3, 1, '李明的餐后血糖平稳计划', '四周内把餐后血糖稳定在8.0mmol/L附近，体重下降1公斤。', '中等风险，家族史和腰围偏高，已有运动改善基础。', '{"diet":"早餐加入蛋白质和蔬菜，午餐外卖优先少油少盐，晚餐主食控制在半碗到一碗。","exercise":"每周5天饭后步行20-30分钟，周末加入一次轻抗阻。","sleep":"保持23点前入睡，减少夜间加餐。"}', '[{"type":"diet","name":"三餐记录并控制含糖饮料"},{"type":"exercise","name":"饭后步行20分钟"}]', '先巩固已经形成的饭后步行习惯，再逐步优化早餐和外卖选择。', 'history', 'success', NULL, '2026-06-26 10:00:00', '2026-06-27 09:30:00'),
(2, 3, 2, 6, 2, '赵晴的稳定随访计划', '保持血糖稳定，减少压力和晚间零食带来的波动。', '低风险但有妊娠期血糖异常史，当前饮食运动规律。', '{"diet":"继续粗细搭配，水果放在两餐之间。","exercise":"保持瑜伽和通勤步行，每周补充2次力量练习。","sleep":"固定睡眠时间，压力大时做5分钟呼吸放松。"}', '[{"type":"diet","name":"记录晚间零食和水果时间"},{"type":"exercise","name":"完成20分钟拉伸或步行"}]', '当前状态较好，重点是避免因为工作压力打乱节奏。', 'active', 'success', NULL, '2026-06-26 10:20:00', '2026-06-26 10:20:00'),
(3, 4, 3, 9, 3, '何燕的血压血糖综合管理计划', '两周内维持每日慢走，减少高盐晚餐，准备线下复查。', '高风险，高血压病史，血糖和腰围均需继续管理。', '{"diet":"晚餐少盐少油，主食以半碗杂粮饭为主，保证蔬菜。","exercise":"饭后慢走15-20分钟，避免突然高强度运动。","monitor":"每周记录3次血压和血糖，复查时给医生查看。"}', '[{"type":"diet","name":"晚餐少盐餐盘记录"},{"type":"exercise","name":"饭后慢走15分钟"}]', '以安全和可持续为先，把慢走、少盐和复查准备做好。', 'active', 'success', NULL, '2026-06-27 10:00:00', '2026-06-27 10:00:00'),
(4, 5, 4, 11, 4, '周博的恢复记录计划', '恢复连续打卡，减少酒精夜宵，完成线下复查。', '高风险且依从性下降，适合管理端随访展示。', '{"diet":"暂停夜宵和含糖饮料，外食优先清淡。","exercise":"从每天10分钟步行恢复，不追求强度。","monitor":"尽快复查血糖、血压和血脂。"}', '[{"type":"diet","name":"避免夜宵和酒精"},{"type":"exercise","name":"恢复10分钟步行"}]', '该计划用于展示停用/随访用户的历史状态。', 'paused', 'success', NULL, '2026-06-18 10:00:00', '2026-06-22 15:00:00');
INSERT INTO life_plans (plan_id, user_id, profile_id, metric_id, assessment_id, plan_title, plan_goal, input_summary, plan_json, checkin_tasks_json, summary, status, call_status, error_message, source_type, source_review_id, create_time, update_time) VALUES
(5, 2, 1, 3, 1, '李明的第2周期自动优化计划', '在保留饭后步行习惯的基础上，把晚餐主食和外卖场景控制得更稳定。', '系统结合李明近6天打卡、餐后血糖趋势和生活方案执行情况自动复盘，判断不需要推翻原方案，只做局部优化。', '{"days":[{"day":1,"diet":"早餐保留鸡蛋和蔬菜，午餐外卖选择少油套餐，晚餐主食半碗。","exercise":"晚餐后步行20分钟，雨天改为室内踏步。"},{"day":2,"diet":"午餐先吃蔬菜和蛋白质，再吃主食，避免含糖饮料。","exercise":"饭后步行25分钟，睡前做5分钟拉伸。"},{"day":3,"diet":"晚餐提前到19点前，主食不超过半碗，增加绿叶菜。","exercise":"饭后轻快步行20分钟，若疲劳则分两段完成。"},{"day":4,"diet":"准备一套固定外卖清单，优先蒸煮炖菜。","exercise":"晚饭后室外步行20-30分钟。"},{"day":5,"diet":"控制零食，把水果放在下午加餐。","exercise":"饭后步行20分钟并记录感受。"},{"day":6,"diet":"复盘本周外卖次数，减少高油高盐菜。","exercise":"加入一次轻抗阻或爬楼替代。"},{"day":7,"diet":"总结一周最容易坚持的三餐搭配。","exercise":"完成一次轻松长步行并准备下周期目标。"}],"diet":"晚餐主食更明确，外卖场景给出可执行替代。","exercise":"保留饭后步行，增加雨天室内替代，避免因天气中断。","monitor":"继续记录空腹和餐后血糖，关注晚餐后波动。"}', '[{"type":"diet","name":"按当日方案记录晚餐主食和外卖选择"},{"type":"exercise","name":"完成当日饭后步行或室内替代"}]', '自动复盘后生成的局部优化方案：保留有效习惯，重点修正雨天运动中断和外卖选择不稳定。', 'active', 'success', NULL, 'auto_intervention', 1, '2026-06-27 09:30:00', '2026-06-27 09:30:00');
