(1, 2, 1, '2026-06-21', '2026-06-26', 6, 6, 5, 91.67, 88, '饮食记录完整，含糖饮料控制好，外卖选择开始更清淡。', '饭后步行完成率高，雨天可准备室内替代方案。', '整体执行稳定，血糖趋势已有改善。', '["雨天运动替代不足", "外卖场景仍需继续优化"]', '["准备室内拉伸或踏步方案", "固定两套少油外卖选择"]', '继续关注餐后血糖和晚餐主食量。', '李明近6天执行情况较好，适合进入巩固阶段。', '6天共12项任务，完成11项。', 'success', NULL, '2026-06-26 21:00:00'),
(2, 3, 2, '2026-06-23', '2026-06-26', 4, 4, 3, 87.50, 84, '晚间零食控制较好，水果时间安排合理。', '运动基本规律，加班日出现一次缺口。', '状态稳定，压力管理是关键。', '["加班影响运动", "睡眠时间偶有后移"]', '["加班日改用10分钟拉伸", "睡前减少屏幕时间"]', '保持规律节奏，不必过度加码。', '赵晴整体表现稳定，适合继续维持。', '4天共8项任务，完成7项。', 'success', NULL, '2026-06-26 21:10:00'),
(3, 4, 3, '2026-06-24', '2026-06-26', 3, 3, 2, 83.33, 80, '少盐和蔬菜摄入改善明显。', '慢走能完成，但需注意膝盖反应。', '高风险用户已有积极变化，仍需线下复查配合。', '["膝盖不适影响运动", "血压血糖仍需复查"]', '["运动强度保持温和", "每周固定记录血压和血糖"]', '准备线下复查资料。', '何燕近期执行度较好，下一步关注安全运动和复查。', '3天共6项任务，完成5项。', 'success', NULL, '2026-06-27 08:30:00'),
(4, 5, 4, '2026-06-17', '2026-06-18', 2, 0, 0, 0.00, 20, '夜宵和饮酒仍未改善。', '运动完全中断。', '依从性下降，需要管理端重点提醒。', '["打卡中断", "应酬饮酒", "缺少复查"]', '["先恢复每日一次记录", "减少夜宵和酒精", "尽快线下复查"]', '恢复登录和基础记录。', '周博处于随访风险较高状态，适合管理端展示异常用户。', '2天共4项任务，完成0项。', 'success', NULL, '2026-06-18 23:30:00');
INSERT INTO `articles` (`article_id`, `title`, `category`, `cover_image`, `summary`, `content`, `status`, `view_count`, `is_recommended`, `sort_order`, `create_time`, `update_time`) VALUES (1,'控糖餐盘怎么搭配：一半蔬菜、适量主食和优质蛋白','diet','/uploads/seed/content/diet-plate.svg','用餐盘法安排蔬菜、主食和蛋白质，帮助日常饮食更清晰。','控糖饮食不等于把餐桌变得很单调。可以先用餐盘法做参照：半盘放非淀粉类蔬菜，如绿叶菜、番茄、黄瓜、菌菇；四分之一放主食，优先选择糙米、燕麦、玉米、全麦面等；另四分之一放鱼、禽、蛋、奶、豆制品或瘦肉。\n\n烹调方式尽量清淡，少用糖醋、红烧浓汁和油炸。先吃蔬菜和蛋白质，再吃主食，部分人会感觉餐后波动更平稳。每个人血糖反应不同，建议结合餐后记录调整份量。如血糖明显异常或需要调整用药，应及时咨询线下医生。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',168,1,101,'2026-06-25 22:20:59','2026-06-26 16:26:47'),(2,'主食不是不能吃：糖友如何选择全谷物和杂豆','diet','/uploads/seed/content/diet-grains.svg','主食要定量也要会选，粗细搭配比完全不吃更可持续。','很多人担心主食升糖，就想完全不吃米饭和面食。实际上，长期不吃主食容易饥饿、乏力，也可能造成下一餐补偿性多吃。更稳妥的做法是控制总量，并把一部分精白主食换成全谷物和杂豆。\n\n可以从三分之一替换开始，例如白米中加入糙米、燕麦米、红豆、鹰嘴豆，或把白面包换成全麦面包。杂粮也含碳水，不能无限量吃。搭配蔬菜和优质蛋白，比单独吃一大碗杂粮饭更合适。若肠胃或肾脏情况特殊，调整前应咨询医生。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',146,1,102,'2026-06-24 22:20:59','2026-06-25 16:26:47'),(3,'水果可以吃，但要会选时间和份量','diet','/uploads/seed/content/diet-fruit.svg','水果不是禁区，关键是种类、份量、时间和个人血糖反应。','糖尿病或高风险人群并不是完全不能吃水果。更推荐选择苹果、梨、柚子、莓果、猕猴桃等相对清爽的水果，控制在小份量，并观察餐后或加餐后的血糖反应。\n\n水果最好放在两餐之间，而不是饭后马上大量吃。果汁、果干、蜜饯虽然看起来和水果有关，但糖分更集中，也更容易吃过量，不建议作为日常替代。吃水果当天，主食和点心也要统筹考虑。如果吃某种水果后血糖反复升高，可以减少份量或换种类，并向医生或营养师咨询。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',139,0,103,'2026-06-23 22:20:59','2026-06-24 16:26:47'),(4,'外出吃饭也能控糖：点餐时注意这几点','diet','/uploads/seed/content/diet-dining.svg','外食时从烹调方式、饮料和主食份量入手，降低餐后波动。','外出吃饭常见问题是油盐多、份量大、饮料甜。点餐时可以优先选择清蒸、炖煮、白灼、少油快炒，少选油炸、糖醋、干锅和浓酱菜。汤汁和蘸料不必全部拌进饭里。\n\n饮料尽量选白水或无糖茶。主食可以先盛半份，搭配蔬菜和蛋白质后再看饱腹感。多人聚餐时，不必每道菜都尝很多，先保证自己能执行的部分。若当天饮食明显超出平时，建议按医嘱监测血糖，身体不适时及时线下就医。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',132,0,104,'2026-06-22 22:20:59','2026-06-23 16:26:47'),(5,'加餐不是零食自由：低糖加餐怎么选','diet','/uploads/seed/content/diet-snack.svg','加餐是为了稳定节奏，不是给甜点、奶茶和饼干开绿灯。','加餐的目的通常是避免两餐间过度饥饿，或配合运动、用药安排，并不代表零食可以随便吃。更适合的选择包括无糖酸奶、少量原味坚果、一个小水果、鸡蛋或少量全麦食品。\n\n奶茶、甜点、夹心饼干、膨化食品容易带来糖和热量超标，即使标注“低糖”也要看配料表。加餐应算进全天总量，份量越简单越容易坚持。若经常需要加餐才能避免低血糖，应记录发生时间和症状，并咨询医生评估用药或进餐安排。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',121,0,105,'2026-06-21 22:20:59','2026-06-22 16:26:47'),(6,'餐后散步为什么适合多数控糖人群','exercise','/uploads/seed/content/exercise-walk.svg','餐后轻中等强度活动有助于改善餐后血糖波动，但要循序渐进。','餐后散步简单、安全门槛低，适合多数需要控糖的人作为日常活动。进餐后不要马上剧烈运动，可以休息片刻，再进行10到20分钟轻中等强度步行，以微微出汗、能说话为宜。\n\n散步的重点是规律，而不是速度越快越好。路线尽量平坦，穿舒适鞋袜，天气太热或太冷时可选择室内走动。若正在使用可能导致低血糖的药物，运动前后更要关注身体反应。出现心慌、头晕、胸闷或明显不适，应停止活动并及时咨询医生。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',174,1,201,'2026-06-25 22:20:59','2026-06-26 16:26:47'),(7,'每周运动怎么安排：有氧、抗阻和拉伸都要有','exercise','/uploads/seed/content/exercise-week.svg','把快走、骑车、弹力带和拉伸组合起来，比单一运动更全面。','控糖运动不只是一味快走。有氧运动能帮助提高能量消耗，抗阻训练有助于保持肌肉量，拉伸则能改善柔韧性和放松状态。三类活动搭配，往往更适合长期坚持。\n\n可以每周安排多次快走、骑车或游泳，再加入2到3次弹力带、靠墙俯卧撑、坐姿抬腿等轻抗阻训练。运动前后做简单拉伸，避免突然开始和突然停止。强度从低到中等逐步增加。若有关节、心血管或其他慢病问题，应先听取医生建议。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',158,1,202,'2026-06-24 22:20:59','2026-06-25 16:26:47'),(8,'久坐人群的控糖运动：从每天多走十分钟开始','exercise','/uploads/seed/content/exercise-office.svg','减少久坐比一次性高强度训练更现实，先把活动嵌进日常。','长时间坐着会让身体代谢变慢，也容易增加体重管理压力。对久坐人群来说，不必一开始就制定很复杂的运动计划，先让每天多动十分钟，就是值得坚持的改变。\n\n可以每坐45到60分钟起身活动几分钟，倒水、走楼梯、原地踏步或做肩颈拉伸。上下班提前一站下车、饭后绕小区走一圈，也能累积活动量。目标是减少连续久坐，而不是周末一次运动补回来。若运动后血糖或身体反应异常，应记录并咨询医生。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',142,0,203,'2026-06-23 22:20:59','2026-06-24 16:26:47'),(9,'运动前后要注意什么：血糖、补水和鞋袜','exercise','/uploads/seed/content/exercise-shoes.svg','运动安全要关注低血糖风险、补水、舒适鞋袜和足部保护。','运动对控糖有帮助，但安全准备同样重要。运动前要了解自己的状态，若空腹、身体不适或血糖波动明显，不宜勉强运动。正在用降糖药或胰岛素的人，更要关注低血糖风险。\n\n运动时适量补水，不要等到明显口渴才喝。鞋袜要舒适透气，避免磨脚，运动后检查足部有没有红肿、水泡或破损。随身带一点应急食物，对容易低血糖的人更稳妥。出现胸闷、头晕、出冷汗等情况，应停止运动并及时处理。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',137,0,204,'2026-06-22 22:20:59','2026-06-23 16:26:47'),(10,'高龄或有慢病的人，运动强度要更保守','exercise','/uploads/seed/content/exercise-elder.svg','年龄较大或合并慢病时，低强度、可持续和安全评估更重要。','高龄人群或合并高血压、冠心病、关节疾病的人，运动目标应更重视安全。适合别人的跑步、爬山或高强度训练，不一定适合自己。先从慢走、太极、八段锦、坐姿训练等低强度活动开始更稳妥。\n\n运动时以呼吸平稳、能交流为宜，不追求大汗淋漓。场地要防滑，最好避开清晨过冷或饭后立刻运动。若近期出现胸痛、气短、头晕、下肢疼痛等情况，应先暂停并就医评估。任何运动计划都应根据个人病情调整。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',126,0,205,'2026-06-21 22:20:59','2026-06-22 16:26:47'),(11,'规律作息对血糖管理有什么帮助','habit','/uploads/seed/content/habit-sleep.svg','睡眠、夜宵和压力都会影响血糖，稳定作息是基础管理。','血糖不只受吃什么影响，睡眠和作息也很关键。熬夜、睡眠不足、夜宵频繁，可能让第二天精神状态和血糖波动都变差。规律作息能帮助身体形成更稳定的代谢节奏。\n\n建议尽量固定睡觉和起床时间，睡前减少浓茶、咖啡和长时间刷手机。晚餐不宜过晚，夜间饥饿时也不要随意吃高糖零食。若长期失眠、打鼾明显或晨起疲惫，应重视睡眠问题。血糖持续异常时，要结合医生建议进行评估。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',151,1,301,'2026-06-25 22:20:59','2026-06-26 16:26:47'),(12,'喝水、饮料和控糖：最推荐的其实是白水','habit','/uploads/seed/content/habit-water.svg','白水和无糖茶更适合日常，含糖饮料容易被忽视。','饮料是很多人控糖时容易忽略的来源。一瓶甜饮、果汁或奶茶，可能在不知不觉中带来较多糖分和能量。日常最推荐的仍然是白水，也可以选择不加糖的淡茶。\n\n运动、天气炎热或出汗较多时，要适量补水。所谓“鲜榨果汁”也不等于可以多喝，因为水果被榨汁后更容易摄入过量。无糖饮料偶尔选择可以，但不建议因此保留嗜甜习惯。若出现明显口渴、多尿或血糖升高，应及时监测并咨询医生。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',138,1,302,'2026-06-24 22:20:59','2026-06-25 16:26:47'),(13,'情绪压力也会影响控糖：给自己一点缓冲','habit','/uploads/seed/content/habit-emotion.svg','压力会影响饮食、睡眠和活动，学会缓冲比硬扛更重要。','情绪紧张时，很多人会睡不好、吃得乱、减少运动，血糖管理也更容易被打乱。压力本身也可能影响身体激素水平，使血糖波动更明显。因此，控糖也需要照顾情绪。\n\n可以从小方法开始：每天做几分钟深呼吸，饭后散步，和家人朋友说说压力，给自己留出固定放松时间。不要因为一次指标不好就过度自责，记录原因并调整下一步更有帮助。若长期焦虑、低落或影响生活，应及时寻求专业帮助。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',119,0,303,'2026-06-23 22:20:59','2026-06-24 16:26:47'),(14,'记录血糖和饮食，能帮你发现自己的规律','habit','/uploads/seed/content/habit-record.svg','把血糖、饮食、运动和睡眠放在一起看，才能找到个人反馈。','同样一餐饭，不同人的血糖反应可能不同。记录能帮助你发现自己的规律，而不是只凭感觉判断。可以记录空腹血糖、餐后血糖、当天主食量、运动、睡眠和特殊情况。\n\n记录不需要很复杂，手机备忘录、健康App或纸本都可以。重点是连续、真实，并在复诊时提供给医生参考。看到波动时先回顾原因，例如是否熬夜、外食、运动减少。不要因为某一次数值就自行调整药物，具体治疗变化应听医生建议。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',162,0,304,'2026-06-22 22:20:59','2026-06-23 16:26:47'),(15,'戒烟限酒和控糖：容易被忽视的生活细节','habit','/uploads/seed/content/habit-clean.svg','烟酒会增加心血管和并发症风险，减少暴露也是控糖管理的一部分。','戒烟限酒常被放在控糖建议的后面，却非常重要。吸烟会增加心血管风险，也可能影响血管和伤口恢复。饮酒则可能带来热量增加、饮食失控或低血糖风险，尤其在空腹饮酒时更需谨慎。\n\n如果一时无法完全戒烟，可以先设定减少目标，避开诱因，并寻求家人或专业门诊帮助。饮酒人群应主动和医生沟通是否适合饮酒及安全范围。把烟酒管理和饮食、运动一起做，长期收益更明显。出现身体不适应及时就医。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',117,0,305,'2026-06-21 22:20:59','2026-06-22 16:26:47'),(16,'什么是糖尿病：先理解血糖为什么会升高','science','/uploads/seed/content/science-meter.svg','用通俗方式理解血糖、胰岛素和长期高血糖风险。','血糖是血液中的葡萄糖，来自食物消化吸收，也来自身体自身调节。胰岛素像一把钥匙，帮助葡萄糖进入细胞被利用。当胰岛素不足，或身体对胰岛素反应变弱时，血糖就可能持续升高。\n\n糖尿病并不可怕到无法管理，但也不能忽视。长期高血糖可能影响眼、肾、神经、心血管等多个方面。早发现、早管理，能帮助降低风险。是否患病、属于哪种类型、是否需要用药，都需要结合检查结果和医生判断，不能只靠症状自行诊断。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',183,1,401,'2026-06-25 22:20:59','2026-06-26 16:26:47'),(17,'1型、2型和妊娠糖尿病有什么区别','science','/uploads/seed/content/science-types.svg','不同类型的原因和管理重点不同，不能靠感觉自行判断。','糖尿病并不是单一类型。1型糖尿病多与胰岛素分泌严重不足有关，通常需要胰岛素治疗。2型糖尿病更常见，常与胰岛素抵抗、体重、年龄、遗传和生活方式有关。妊娠糖尿病则发生在妊娠期间，需要同时关注母婴安全。\n\n不同类型的治疗和随访重点不同，不能只凭年龄、胖瘦或症状判断。即使血糖暂时不高，也要按医生建议复查。了解分类的意义，是帮助自己配合检查和管理，而不是自行给自己下结论或随意用药。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',141,1,402,'2026-06-24 22:20:59','2026-06-25 16:26:47'),(18,'糖尿病前期是什么意思：它不是小事，也不是绝望','science','/uploads/seed/content/science-prediabetes.svg','糖尿病前期提示风险升高，但生活方式干预仍有重要价值。','糖尿病前期是指血糖已经高于理想水平，但尚未达到糖尿病诊断标准的状态。它不是“小问题不用管”，也不是“已经没办法”。这个阶段及时行动，往往能帮助降低进一步发展的风险。\n\n管理重点包括体重控制、规律运动、减少含糖饮料、调整主食结构、改善睡眠和定期复查。不要因为没有明显症状就忽视，也不要自行购买药物或保健品。复查项目和频率应听医生建议。把它当成一次提醒，越早建立习惯越有主动权。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',136,0,403,'2026-06-23 22:21:00','2026-06-24 16:26:47'),(19,'空腹血糖和餐后血糖，分别看什么','science','/uploads/seed/content/science-glucose.svg','空腹和餐后指标反映不同侧面，结合趋势更有参考价值。','空腹血糖通常反映基础状态，容易受前一晚饮食、睡眠、肝糖输出等因素影响。餐后血糖则更能反映一餐饭后的身体反应，和主食种类、份量、进餐速度以及饭后活动有关。\n\n有些人空腹血糖不高，但餐后波动明显；也有人清晨数值偏高，需要进一步分析原因。单次测量不能代表全部，连续记录趋势更有意义。检测时间、仪器使用和手部清洁也会影响结果。具体目标范围和处理方式，应根据医生建议确定。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',129,0,404,'2026-06-22 22:21:00','2026-06-23 16:26:47'),(20,'BMI、腰围和糖尿病风险有什么关系','science','/uploads/seed/content/science-bmi.svg','体重和中心型肥胖会影响代谢风险，目标要合理可持续。','BMI和腰围是评估代谢风险的常用参考。尤其是腰腹部脂肪增加时，身体对胰岛素的反应可能变弱，糖尿病和心血管风险也可能上升。关注体重不是为了追求过瘦，而是为了改善整体健康。\n\n减重目标应现实，先减少5%到10%的体重，对部分人就可能带来积极变化。方法上仍是饮食结构、总量控制、规律运动和睡眠管理。不要使用极端节食或来路不明产品。若合并慢病或体重变化异常，应咨询医生。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',124,0,405,'2026-06-21 22:21:00','2026-06-22 16:26:47'),(21,'为什么糖尿病管理不只看血糖，还要看血压和血脂','complication','/uploads/seed/content/complication-pressure.svg','心血管风险需要综合管理，血糖、血压、血脂都值得关注。','糖尿病管理不是只盯着血糖。血压、血脂、体重、吸烟情况和家族史都会影响心血管风险。即使血糖控制还不错，如果血压和血脂长期异常，也可能增加并发症风险。\n\n建议定期复查血压、血脂、肾功能等指标，把结果保存下来，复诊时便于医生判断趋势。日常饮食少油少盐，减少加工食品，保持规律活动。是否需要用药、目标设定多少，都要结合个人情况。出现胸痛、气短等症状应及时就医。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',157,1,501,'2026-06-25 22:21:00','2026-06-26 16:26:47'),(22,'眼部检查不能忽视：视网膜健康需要定期关注','complication','/uploads/seed/content/complication-eye.svg','眼底问题早期可能没有感觉，定期眼科随访很重要。','糖尿病相关眼部问题早期可能没有明显症状，等到视物模糊、黑影或视力下降时，问题可能已经持续了一段时间。因此，定期眼底检查是预防和早发现的重要环节。\n\n眼部健康也受血压、血脂和血糖波动影响，不能只靠滴眼药水或休息解决。若出现视物变形、突然看不清、闪光感等情况，应尽快就医。平时按医嘱复查，保持综合指标稳定，比等症状出现后再处理更稳妥。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',148,1,502,'2026-06-24 22:21:00','2026-06-25 16:26:47'),(23,'糖尿病足如何预防：每天看看脚很重要','complication','/uploads/seed/content/complication-foot.svg','足部检查、鞋袜选择和伤口处理，是每天都能做的预防。','长期血糖异常可能影响神经和血管，足部小伤口也需要认真对待。每天洗脚后看一看脚底、脚趾缝、足跟和指甲周围，是否有红肿、水泡、破损、颜色变化或疼痛。\n\n鞋袜要合脚、透气，不要赤脚走路，新鞋不要一次穿太久。修剪指甲时避免剪得过深。若有鸡眼、老茧或伤口，不建议自行用刀片处理。伤口不愈合、渗液、红肿或疼痛加重时，应及时到医院处理。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',143,0,503,'2026-06-23 22:21:00','2026-06-24 16:26:47'),(24,'肾脏健康与糖尿病：早期筛查更安心','complication','/uploads/seed/content/complication-kidney.svg','尿检、肾功能和血压管理能帮助更早发现肾脏风险。','肾脏负责过滤代谢废物，长期血糖和血压控制不佳会增加肾脏负担。早期肾脏问题可能没有明显不适，因此不能只凭感觉判断是否安全。\n\n定期检查尿微量白蛋白、肾功能和血压，有助于早发现风险。日常饮食注意少盐，避免随意使用止痛药、偏方或不明保健品，以免增加肾脏负担。若检查提示异常，应按医生建议复查和治疗。保护肾脏靠长期综合管理，不是临时补救。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',126,0,504,'2026-06-22 22:21:00','2026-06-23 16:26:47'),(25,'口腔和皮肤也要管：小问题别拖成大麻烦','complication','/uploads/seed/content/complication-skin.svg','牙龈、皮肤感染和小伤口都值得关注，清洁和就医要及时。','血糖长期不稳定时，口腔和皮肤问题也可能增多。牙龈出血、口腔异味、皮肤瘙痒、反复感染或小伤口愈合慢，都不应长期拖着。\n\n日常要坚持刷牙、使用牙线或冲牙器，定期口腔检查。皮肤保持清洁和干燥，避免抓挠导致破损。脚部、腹股沟等容易潮湿的部位更要留意。若出现红肿、化脓、发热或伤口不愈合，应及时就医，不要自行乱用药膏。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',118,0,505,'2026-06-21 22:21:00','2026-06-22 16:26:47'),(26,'误区一：不吃主食就能控糖吗','mistake','/uploads/seed/content/mistake-rice.svg','主食不能完全取消，选择种类和控制份量更重要。','不吃主食看似能让血糖短期下降，但很难长期坚持，也可能带来饥饿、乏力、营养不均衡和暴食反弹。主食不是控糖的敌人，关键在于种类、份量和搭配。\n\n建议减少精白米面的大份量摄入，适当加入全谷物、杂豆和薯类。每餐主食不要单独吃，搭配蔬菜和优质蛋白更稳。若需要更严格的碳水控制，应在医生或营养师指导下进行。不要自行采用极端饮食，更不要因此随意调整药物。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',176,1,601,'2026-06-25 22:21:00','2026-06-26 16:26:47'),(27,'误区二：无糖食品可以随便吃吗','mistake','/uploads/seed/content/mistake-label.svg','无糖不等于无热量，也不代表可以不看配料和总量。','“无糖”常让人放松警惕，但无糖食品不一定低热量，也可能含有较多淀粉、脂肪或钠。饼干、糕点、饮料即使不添加蔗糖，也不等于可以无限量吃。\n\n购买时要看营养成分表，关注能量、碳水化合物、脂肪和配料顺序。代糖可以帮助减少糖摄入，但不应成为保持嗜甜习惯的理由。更重要的是把天然食物、规律三餐和总量控制放在前面。吃后血糖波动明显时，应减少或避免。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',154,1,602,'2026-06-24 22:21:00','2026-06-25 16:26:47'),(28,'误区三：只靠保健品就能降糖吗','mistake','/uploads/seed/content/mistake-supplement.svg','保健品不能替代饮食、运动、监测和正规治疗。','一些产品会宣传“快速降糖”“停药不反弹”，这类说法需要格外谨慎。糖尿病或糖尿病前期管理，不能建立在单一保健品上，更不能用它替代医生制定的治疗方案。\n\n正规管理包括饮食、运动、体重、睡眠、血糖监测和必要药物。保健品也可能和药物相互影响，或增加肝肾负担。购买前应看清批准信息和成分，不相信绝对化承诺。若血糖异常，应及时线下就医，而不是拖延治疗。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',149,0,603,'2026-06-23 22:21:00','2026-06-24 16:26:47'),(29,'误区四：血糖正常了就可以停药吗','mistake','/uploads/seed/content/mistake-medicine.svg','指标改善不等于可以自行停药，治疗调整要和医生沟通。','看到血糖正常几次，有些人会想自行停药。实际上，指标变好可能正是饮食、运动和药物共同作用的结果。突然停药可能让血糖再次升高，甚至带来更大波动。\n\n是否减药、停药或换药，需要结合血糖记录、糖化血红蛋白、低血糖风险、并发症和整体健康情况判断。复诊时可以主动把记录给医生看，一起讨论方案。生活方式仍要坚持，不要把“正常一次”理解成风险消失。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',133,0,604,'2026-06-22 22:21:00','2026-06-23 16:26:47'),(30,'误区五：运动越猛越好吗','mistake','/uploads/seed/content/mistake-exercise.svg','过度运动可能带来低血糖和损伤风险，适合自己才重要。','运动有益控糖，但不是越猛越好。突然进行高强度跑步、长时间爬山或空腹运动，可能导致低血糖、关节损伤或心血管风险，尤其是平时活动少或已有慢病的人。\n\n更推荐循序渐进：先从散步、骑车、拉伸和轻抗阻开始，逐步增加时间和强度。运动前后关注血糖、补水和足部情况。出现头晕、心慌、胸闷或出冷汗，应立即停止并处理。运动计划最好结合医生建议制定。\n\n建议先选择一两项最容易执行的做法，坚持记录饮食、活动和血糖变化，再根据反馈逐步调整。若血糖明显异常、身体不适或需要调整用药，应及时咨询线下医生。','published',128,0,605,'2026-06-21 22:21:00','2026-06-22 16:26:47');
INSERT INTO `home_contents` (`content_id`, `content_type`, `title`, `subtitle`, `image_url`, `link_type`, `link_value`, `sort_order`, `status`, `created_by`, `create_time`, `update_time`) VALUES (1,'banner','从今天开始稳稳控糖','饮食、运动和监测一起做，逐步建立适合自己的健康节奏。','/uploads/seed/content/banner-prevention.svg','none','',1,'enabled',NULL,'2026-06-26 22:21:00','2026-06-27 16:26:47'),(2,'banner','低糖餐盘也可以很好吃','学会搭配全谷物、蔬菜和优质蛋白，让每一餐更安心。','/uploads/seed/content/banner-diet.svg','none','',2,'enabled',NULL,'2026-06-26 22:21:00','2026-06-27 16:26:47'),(3,'banner','AI 助手陪你记录健康变化','结合健康档案和生活方案，及时发现需要关注的指标。','/uploads/seed/content/banner-ai.svg','life_plan','',3,'enabled',NULL,'2026-06-26 22:21:00','2026-06-27 16:26:47');
INSERT INTO `ai_experts` (`expert_id`, `expert_name`, `title`, `department`, `avatar_url`, `specialty`, `persona`, `opening_message`, `sort_order`, `status`, `create_time`, `update_time`) VALUES (1,'林清禾','主任医师','内分泌代谢科','','糖尿病综合管理、血糖指标解读、并发症风险提醒','你是林清禾，糖尿病预治智能助手中的内分泌代谢科主任医师型 AI 专家。你擅长用严谨但容易理解的方式解释血糖、血压、体重、风险评估和生活方式干预。回答时先说明自己是林清禾，再结合用户健康数据给出安全、可执行的建议。','你好，我是林清禾，内分泌代谢科方向的 AI 专家。我可以帮你解释血糖、风险评估和控糖方案。',10,'enabled','2026-06-27 13:57:13','2026-06-27 13:57:13'),(2,'周明远','营养管理师','控糖营养门诊','','饮食结构、餐盘搭配、体重管理','你是周明远，糖尿病预治智能助手中的控糖营养管理 AI 专家。你擅长把饮食建议转化成清晰的餐盘搭配、替换方案和一日饮食节奏。回答时先说明自己是周明远，重点从饮食、体重和餐后血糖角度给出建议。','你好，我是周明远，控糖营养方向的 AI 专家。我可以帮你调整饮食结构和餐盘搭配。',20,'enabled','2026-06-27 13:57:13','2026-06-27 13:57:13'),(3,'许安宁','运动康复师','运动与生活方式门诊','','运动计划、打卡习惯、生活方式改善','你是许安宁，糖尿病预治智能助手中的运动康复与生活方式 AI 专家。你擅长根据用户运动基础、打卡完成率和健康指标，给出温和、循序渐进、可坚持的运动和生活方式建议。回答时先说明自己是许安宁。','你好，我是许安宁，运动康复与生活方式方向的 AI 专家。我可以帮你制定更容易坚持的运动和打卡节奏。',30,'enabled','2026-06-27 13:57:13','2026-06-27 13:57:13');
